// src/pages/Internship.jsx
import React, { useEffect, useState } from "react";
import axios from "axios";
import "./Internship.css";

export default function Internship() {
  const [internships, setInternships] = useState([]);
  const [applications, setApplications] = useState([]);
  const [searchQuery, setSearchQuery] = useState("");
  const [locationFilter, setLocationFilter] = useState("");
  const [showModal, setShowModal] = useState(false);
  const [editingInternship, setEditingInternship] = useState(null);

  const user = JSON.parse(localStorage.getItem("currentUser"));

  const initialFormData = {
    title: "",
    description: "",
    location: "",
    stipend: "",
    duration: "",
    company: "",
  };

  const [formData, setFormData] = useState(initialFormData);

  useEffect(() => {
    fetchInternships();
    if (user?.role === "student") {
      fetchApplications();
    }
  }, []);

  const fetchInternships = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/internships");
      setInternships(res.data);
    } catch (error) {
      console.error("Error fetching internships:", error);
    }
  };

  const fetchApplications = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/applications", {
        headers: {
          Authorization: `Bearer ${user?.token}`,
        },
      });
      setApplications(res.data);
    } catch (error) {
      console.error("Error fetching applications:", error);
    }
  };

  const handleOpenModal = () => {
    setShowModal(true);
    setEditingInternship(null);
    setFormData(initialFormData);
  };

  const handleCloseModal = () => {
    setShowModal(false);
  };

  const handleAddInternship = async () => {
    try {
      const res = await axios.post("http://localhost:5000/api/internships", formData, {
        headers: {
          Authorization: `Bearer ${user?.token}`,
        },
      });
      setInternships([...internships, res.data]);
      setShowModal(false);
      setFormData(initialFormData);
    } catch (error) {
      console.error("Error adding internship:", error);
    }
  };

  const handleEditInternship = (internship) => {
    setEditingInternship(internship);
    setFormData(internship);
    setShowModal(true);
  };

  const handleUpdateInternship = async () => {
    try {
      const res = await axios.put(
        `http://localhost:5000/api/internships/${editingInternship._id}`,
        formData,
        {
          headers: {
            Authorization: `Bearer ${user?.token}`,
          },
        }
      );
      const updatedList = internships.map((item) =>
        item._id === editingInternship._id ? res.data : item
      );
      setInternships(updatedList);
      setShowModal(false);
      setEditingInternship(null);
      setFormData(initialFormData);
    } catch (error) {
      console.error("Error updating internship:", error);
    }
  };

  const handleDeleteInternship = async (id) => {
    try {
      await axios.delete(`http://localhost:5000/api/internships/${id}`, {
        headers: {
          Authorization: `Bearer ${user?.token}`,
        },
      });
      setInternships(internships.filter((item) => item._id !== id));
    } catch (error) {
      console.error("Error deleting internship:", error);
    }
  };

  const handleApply = async (id) => {
    try {
      await axios.post(
        `http://localhost:5000/api/applications`,
        { internshipId: id },
        {
          headers: {
            Authorization: `Bearer ${user?.token}`,
          },
        }
      );
      alert("Applied successfully!");
      fetchApplications();
    } catch (error) {
      console.error("Error applying:", error);
    }
  };

  const isApplied = (id) => {
    return applications.some((app) => app.internshipId === id);
  };

  const filteredInternships = internships.filter((item) =>
    item.title.toLowerCase().includes(searchQuery.toLowerCase()) &&
    item.location.toLowerCase().includes(locationFilter.toLowerCase())
  );

  return (
    <div className="internship-page">
      <h2>Internships</h2>

      <div className="filters">
        <input
          type="text"
          placeholder="Search by title"
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
        />
        <input
          type="text"
          placeholder="Filter by location"
          value={locationFilter}
          onChange={(e) => setLocationFilter(e.target.value)}
        />
        {(user?.role === "admin" || user?.role === "hr") && (
          <button onClick={handleOpenModal} className="add-internship-btn">
            + Add Internship
          </button>
        )}
      </div>

      <div className="internship-list">
        {filteredInternships.map((item) => (
          <div key={item._id} className="internship-card">
            <h3>{item.title}</h3>
            <p><strong>Company:</strong> {item.company}</p>
            <p><strong>Location:</strong> {item.location}</p>
            <p><strong>Duration:</strong> {item.duration}</p>
            <p><strong>Stipend:</strong> {item.stipend}</p>
            <p>{item.description}</p>
            {user?.role === "student" && (
              <button
                className="apply-btn"
                onClick={() => handleApply(item._id)}
                disabled={isApplied(item._id)}
              >
                {isApplied(item._id) ? "Applied" : "Apply"}
              </button>
            )}
            {(user?.role === "admin" || user?.role === "hr") && (
              <div className="actions">
                <button onClick={() => handleEditInternship(item)}>Edit</button>
                {user?.role === "admin" && (
                  <button onClick={() => handleDeleteInternship(item._id)}>Delete</button>
                )}
              </div>
            )}
          </div>
        ))}
      </div>

      {showModal && (
        <div className="modal">
          <div className="modal-content">
            <h3>{editingInternship ? "Edit Internship" : "Add Internship"}</h3>
            <input
              type="text"
              placeholder="Title"
              value={formData.title}
              onChange={(e) => setFormData({ ...formData, title: e.target.value })}
            />
            <input
              type="text"
              placeholder="Company"
              value={formData.company}
              onChange={(e) => setFormData({ ...formData, company: e.target.value })}
            />
            <input
              type="text"
              placeholder="Location"
              value={formData.location}
              onChange={(e) => setFormData({ ...formData, location: e.target.value })}
            />
            <input
              type="text"
              placeholder="Stipend"
              value={formData.stipend}
              onChange={(e) => setFormData({ ...formData, stipend: e.target.value })}
            />
            <input
              type="text"
              placeholder="Duration"
              value={formData.duration}
              onChange={(e) => setFormData({ ...formData, duration: e.target.value })}
            />
            <textarea
              placeholder="Description"
              value={formData.description}
              onChange={(e) => setFormData({ ...formData, description: e.target.value })}
            />
            <div className="modal-actions">
              {!editingInternship ? (
                <button onClick={handleAddInternship}>Save</button>
              ) : (
                <button onClick={handleUpdateInternship}>Update</button>
              )}
              <button onClick={handleCloseModal}>Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
